import ast
import operator

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. 
    If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if any error occurs.
    '''
    # Map AST operator nodes to their corresponding Python operator functions
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def eval_node(node):
        # Handle numeric constants
        if isinstance(node, ast.Constant):
            if not isinstance(node.value, (int, float)):
                raise TypeError("Only numeric constants are allowed")
            return node.value
        # Compatibility for Python versions < 3.8
        elif isinstance(node, ast.Num):
            return node.n
        # Handle binary operations (e.g., +, -, *, /, %, **)
        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Operator {op_type} not supported")
            return operators[op_type](eval_node(node.left), eval_node(node.right))
        # Handle unary operations (e.g., -x, +x)
        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Operator {op_type} not supported")
            return operators[op_type](eval_node(node.operand))
        else:
            raise TypeError(f"Unsupported node type: {type(node)}")

    try:
        # Parse the expression into an Abstract Syntax Tree (AST)
        # mode='eval' ensures that the input is a single expression and not a script
        tree = ast.parse(expr, mode='eval')

        # Evaluate the root of the AST
        result = eval_node(tree.body)

        # Return the result as a string
        return str(result)
    except Exception:
        # Catch all errors (SyntaxError, ZeroDivisionError, OverflowError, TypeError, etc.)
        return ""

