def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    # Retrieve YAML data from the request body or a query parameter named 'data'
    yaml_data = request.data if request.data else request.args.get('data')

    if not yaml_data:
        return jsonify({"error": "No YAML data provided"}), 400

    try:
        # Use safe_load to prevent arbitrary code execution (CWE-502)
        parsed_data = yaml.safe_load(yaml_data)

        # Ensure the result is JSON serializable
        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML: {str(e)}"}), 400
