def hash_password(hash_name: str, password: bytes) -> bytes:
    """
    Securely hashes the given password using the specified hash algorithm.
    Prevents the use of insecure algorithms like md5 and sha1.
    """
    if hash_name not in hashlib.algorithms_available:
        raise ValueError(f"Hash algorithm {hash_name} is not available")

    # List of insecure algorithms to block
    insecure_algorithms = {'md5', 'sha1'}
    if hash_name.lower() in insecure_algorithms:
        raise ValueError(f"Hash algorithm {hash_name} is insecure and not allowed")

    # Create the hash object and return the digest
    hasher = hashlib.new(hash_name, password)
    return hasher.digest()

